mapper.select:
SELECT id, stat_date, stat_type, granularity, subject_type, subject_value,
       total_reservations, approved_reservations, rejected_reservations, cancelled_reservations,
       expired_reservations, total_borrows, total_returns, total_overdue, total_overdue_hours,
       utilization_rate, created_at, updated_at
FROM statistics_daily
WHERE stat_date = #{statDate}
  AND stat_type = #{statType}
  AND subject_type = #{subjectType}
ORDER BY subject_value ASC
